Create the `TaskReconciler` that runs on a 5-minute interval to sync file state to the DB, following the agent reconciler pattern.

## File location

`apps/server/src/services/tasks/task-reconciler.ts`

## Implementation

```typescript
import fs from 'node:fs/promises';
import path from 'node:path';
import type { MeshCore } from '@dorkos/mesh';
import type { TaskStore } from './task-store.js';
import { parseTaskFile, isParseError } from './task-file-parser.js';
import { createTaggedLogger } from '../../lib/logger.js';

const logger = createTaggedLogger('TaskReconciler');

/** How often to reconcile (5 minutes). */
const RECONCILE_INTERVAL_MS = 300_000;

/** How long to keep DB entries after their file is removed (24 hours). */
const GRACE_PERIOD_MS = 86_400_000;

/**
 * Safety-net reconciler that syncs task files to the DB cache.
 *
 * Runs every 5 minutes. Handles cases the file watcher might miss:
 * network-mounted filesystems, rapid restarts, manual DB edits.
 * Follows the agent reconciler pattern from packages/mesh/src/reconciler.ts.
 */
export class TaskReconciler {
  private timer: ReturnType<typeof setInterval> | null = null;

  constructor(
    private store: TaskStore,
    private meshCore: MeshCore,
    private dorkHome: string,
    private onTaskChange: (taskId: string) => void,
  ) {}

  /** Start the reconciliation loop. */
  start(): void {
    if (this.timer) return;
    this.timer = setInterval(() => void this.reconcile(), RECONCILE_INTERVAL_MS);
    logger.info('Task reconciler started (5-minute interval)');
  }

  /** Stop the reconciliation loop. */
  stop(): void {
    if (this.timer) {
      clearInterval(this.timer);
      this.timer = null;
      logger.info('Task reconciler stopped');
    }
  }

  /** Run a single reconciliation cycle. Exposed for testing. */
  async reconcile(): Promise<void> {
    try {
      const taskDirs = this.getTaskDirectories();
      const fileTaskIds = new Set<string>();

      for (const { dir, scope, projectPath } of taskDirs) {
        try {
          const files = await fs.readdir(dir);
          for (const file of files) {
            if (!file.endsWith('.md')) continue;
            const filePath = path.join(dir, file);
            try {
              const content = await fs.readFile(filePath, 'utf-8');
              const result = parseTaskFile(filePath, content, scope, projectPath);
              if (isParseError(result)) {
                logger.warn(`Reconciler: invalid task file ${filePath}: ${result.error}`);
                continue;
              }
              fileTaskIds.add(result.id);
              this.store.upsertFromFile(result);
              this.onTaskChange(result.id);
            } catch (err) {
              logger.error(`Reconciler: failed to read ${filePath}`, err);
            }
          }
        } catch {
          // Directory doesn't exist yet — normal for projects without tasks
        }
      }

      // Clean up orphan DB entries
      this.cleanupOrphans(fileTaskIds);
    } catch (err) {
      logger.error('Reconciler cycle failed', err);
    }
  }

  /**
   * Get all task directories to scan:
   * - Global: {dorkHome}/tasks/
   * - Per-agent: {agent.projectPath}/.dork/tasks/
   */
  private getTaskDirectories(): Array<{
    dir: string;
    scope: 'project' | 'global';
    projectPath?: string;
  }> {
    const dirs: Array<{ dir: string; scope: 'project' | 'global'; projectPath?: string }> = [
      { dir: path.join(this.dorkHome, 'tasks'), scope: 'global' },
    ];

    // Get all registered agents and add their task directories
    const agents = this.meshCore.list();
    for (const agent of agents) {
      if (agent.projectPath) {
        dirs.push({
          dir: path.join(agent.projectPath, '.dork', 'tasks'),
          scope: 'project',
          projectPath: agent.projectPath,
        });
      }
    }

    return dirs;
  }

  /**
   * Remove DB entries whose files no longer exist, respecting the 24h grace period.
   */
  private cleanupOrphans(activeFileIds: Set<string>): void {
    const allTasks = this.store.listTasks();
    const now = Date.now();

    for (const task of allTasks) {
      if (activeFileIds.has(task.id)) continue; // File exists — skip

      // Task is in DB but not on disk
      if (task.status !== 'paused') {
        // First detection — mark as paused
        this.store.markRemovedBySlug(task.id);
        this.onTaskChange(task.id);
      } else {
        // Already paused — check grace period
        const updatedAt = new Date(task.updatedAt).getTime();
        if (now - updatedAt > GRACE_PERIOD_MS) {
          // Past grace period — delete from DB
          this.store.deleteTask(task.id);
          logger.info(`Removed orphan task: ${task.id} (past 24h grace period)`);
        }
      }
    }
  }
}
```

