## ensureDefaultTemplates()

```typescript
import fs from 'node:fs/promises';
import path from 'node:path';
import { writeTaskFile } from './task-file-writer.js';
import { createTaggedLogger } from '../../lib/logger.js';

const logger = createTaggedLogger('TaskTemplates');

/**
 * Seed default task templates if the templates directory is empty.
 *
 * Called during server startup. Idempotent — if any .md files already
 * exist in the templates directory, seeding is skipped.
 *
 * @param dorkHome - Resolved data directory path
 */
export async function ensureDefaultTemplates(dorkHome: string): Promise<void> {
  const templatesDir = path.join(dorkHome, 'tasks', 'templates');
  await fs.mkdir(templatesDir, { recursive: true });

  const existing = await fs.readdir(templatesDir);
  if (existing.some((f) => f.endsWith('.md'))) {
    logger.debug('Templates already seeded — skipping');
    return;
  }

  for (const template of DEFAULT_TEMPLATES) {
    await writeTaskFile(templatesDir, template.slug, template.frontmatter, template.prompt);
  }

  logger.info(`Seeded ${DEFAULT_TEMPLATES.length} default templates`);
}
```

## loadTemplates()

Add a function to read and parse template files for the `GET /api/tasks/templates` endpoint:

```typescript
import { parseTaskFile, isParseError } from './task-file-parser.js';

export interface TaskTemplate {
  slug: string;
  name: string;
  description: string;
  prompt: string;
  cron: string;
  timezone?: string;
  tags?: string[];
}

/**
 * Load all template files from the templates directory.
 *
 * @param dorkHome - Resolved data directory path
 * @returns Array of parsed templates
 */
export async function loadTemplates(dorkHome: string): Promise<TaskTemplate[]> {
  const templatesDir = path.join(dorkHome, 'tasks', 'templates');

  try {
    const files = await fs.readdir(templatesDir);
    const templates: TaskTemplate[] = [];

    for (const file of files) {
      if (!file.endsWith('.md')) continue;
      const filePath = path.join(templatesDir, file);
      const content = await fs.readFile(filePath, 'utf-8');
      const result = parseTaskFile(filePath, content, 'global');
      if (isParseError(result)) continue;

      templates.push({
        slug: result.id,
        name: result.meta.name,
        description: result.meta.description ?? '',
        prompt: result.prompt,
        cron: result.meta.cron ?? '',
        timezone: result.meta.timezone,
        tags: result.meta.tags,
      });
    }

    return templates;
  } catch {
    return []; // Directory doesn't exist yet
  }
}
```

