```typescript
router.post('/', async (req, res) => {
  const body = CreateTaskRequestSchema.parse(req.body);
  const slug = toKebabCase(body.name);

  // Resolve target directory
  let tasksDir: string;
  let scope: 'project' | 'global' = 'global';
  let projectPath: string | undefined;

  if (body.agentId && body.agentId !== 'damon') {
    const agent = meshCore.get(body.agentId);
    if (!agent) return res.status(404).json({ error: 'Agent not found' });
    tasksDir = path.join(agent.projectPath, '.dork', 'tasks');
    scope = 'project';
    projectPath = agent.projectPath;
  } else {
    tasksDir = path.join(dorkHome, 'tasks');
  }

  // Build frontmatter
  const frontmatter: TaskFrontmatter = {
    name: body.name,
    description: body.description,
    cron: body.cron ?? undefined,
    timezone: body.timezone ?? 'UTC',
    agent: body.agentId,
    enabled: body.enabled ?? true,
    maxRuntime: body.maxRuntime ? formatDuration(body.maxRuntime) : undefined,
    permissions: (body.permissionMode as 'acceptEdits' | 'bypassPermissions') ?? 'acceptEdits',
    tags: body.tags ?? [],
  };

  // Write file atomically
  const filePath = await writeTaskFile(tasksDir, slug, frontmatter, body.prompt);

  // Sync to DB immediately
  const def: TaskDefinition = {
    id: slug, meta: frontmatter, prompt: body.prompt,
    scope, filePath, projectPath,
  };
  store.upsertFromFile(def);

  // Register cron if present
  const task = store.getBySlug(slug)!;
  if (task.cron) taskScheduler.registerTask(task);

  const nextRun = taskScheduler.getNextRun(slug);
  return res.status(201).json({ ...task, nextRun });
});
```

